function.textSource:
      function CF_TITEMPRESAFormula return VARCHAR2 is

   vTitEmpresa varchar2(80);
   vTexto      varchar2(80);

begin
   select tit_reportes 
   into   vTitEmpresa
   from   empresa
   where  cod_empresa = :pg_cOD_EMPRESA;

   return  upper(vTitEmpresa);
exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000046'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_coD_IDIOMA;

        SRW.message(0, 'PA-000046 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TitSistemaFormula return VARCHAR2 is
   vTitSistema varchar2(80);
   vTexto      varchar2(80);
begin
   select  titulo
   into    vTitSistema
   from    titulos_sistemas
   where   cod_sistema = :pg_COD_SISTEMA
     and   cod_idioma  = :pg_COD_IDIOMA;

   return upper(vTitSistema);

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000048'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000048 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TitAgenciaFormula return VARCHAR2 is

   vTitAgencia varchar2(80);
   vTexto      varchar2(80);

begin

   select descripcion
   into   vTitAgencia
   from   agencia
   where  cod_empresa = :pg_COD_EMPRESA
     and  cod_agencia = :pg_COD_AGENCIA;

   return upper(vTitAgencia); 

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000045'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000045 ' || vTexto);
        raise SRW.program_abort;
end;

      function CF_TitReporteFormula return VARCHAR2 is
   vTitReporte varchar2(80);
   vTexto      varchar2(80);

begin
   select titulo || ' Cliente: ' || :p_cod_cliente || ' ' || F_RET_NOM_CLIENTE(:p_cod_cliente)
   into   vTitReporte
   from   titulos_reportes
   where  nom_reporte = :pg_NOM_REPORTE
     and  cod_idioma  = :pg_COD_IDIOMA;

   return vTitReporte;

exception

   when SRW.NO_DATA_FOUND then

      select texto
      into   vTexto
      from   mensajes_sistema
      where  num_mensaje  = '000047'
        and  cod_sistema  = 'PA'
        and  cod_idioma   = :pg_COD_IDIOMA;

        SRW.message(0, 'PA-000047 ' || vTexto);
        raise SRW.program_abort;

end;

      function CF_TipocambioFormula return Number is
   v_tipcamb number(16,2);
   v_mensaje varchar2(100);
begin
    begin
		    Cg_Utl.Obtiene_TC_Conta(1, :sysdate, v_tipcamb, v_mensaje);
    exception
        when others then
          v_tipcamb := null;
    end;
    return v_tipcamb;
end;

      function BeforeReport return boolean is
	v_error varchar2(3000);
begin
  pr.Carga_Prr0402M(
        :p_cod_cliente,
        :p_fecha_hoy,
        v_error
    );
   IF v_error IS NOT NULL THEN
       return (FALSE);
    END IF;
  return (TRUE);
end;
